def select_provider(task):
    """Reject provider-backed LLM routing in packaged plugin runtimes."""

    raise RuntimeError(
        "Provider-backed LLM calls are disabled in local plugin runtimes. "
        f"Use Codex for semantic judgment instead of resolving query step {task!r}."
    )


