def get_run_params():
    """
    Creates dictionary with parameters for running session.

    Logging flags:
    - show_user_errors: if True, display UI error boxes.
    - log_to_console: if True, enable console logs (stdout).
    - log_to_file: if True, write logs to logs/app.log.
    - log_file_max_bytes: rotate log file at the given size.
    - log_file_backup_count: number of rotated log files to keep.
    """
    runParams = {
        "checkCollect": False,
        "runChecksAndBold": True,
        "beneficiaryCheckMode": "compare",
        "printErrorDetails": True,
        "disableUpload": False,
        "checkIfMoveRowsFound": True,
        "trackProcessingTime": True,  # False
        "trackMemoryUsage": True,
        "checkIfDuplicates": False,  #  in different steps of processing checks for duplicate values
        "normalizeMean": True,  # , z score or min max
        "makeColsCategorical": True,
        "includeBaseDataframe": True,
        "checkVariance": False,  # False
        "saveDatasetSteps": False,  # for testing, save data at each step of data preparation
        "saveRecalculationSteps": False,  # for testing, saves data at each step of each loop
        "deleteHierarchicalParents": True,
        "replaceAllWithBlanc": True,
        "checkDateColName": True,  # if False just checks if column format is date, if true also checks date column name
        "numberOfRowsDetailed": 100000000000,
        "maxDfLengthForDetails": 30000000000,
        "titleOnThreeRows": True,
        "runOpenAI": True,
        "llmBatchMode": True,
        # Attribute classification: enable second-pass retry of unknowns
        # Set False to skip the fallback (reduces extra LLM calls)
        "attrClassificationRetryUnknowns": True,
        # Auto-apply synonyms from review queue after classification (LLM required)
        # Default OFF: suggestions visible in Review tab; Apply triggers writes.
        "autoApplySynonyms": False,
        # When True, treat cached 'not in taxonomy' values as missing and re-classify
        "attrReclassifyNotInTaxonomy": False,
        "show_user_errors": False,
        "log_to_console": True,
        "log_to_file": True,
        "log_file_max_bytes": 5_000_000,
        "log_file_backup_count": 5,
        "salesApiUrl": os.environ.get("SALES_API_URL", "http://localhost:8000"),
    }
    return runParams


